class dividends_table extends DB_Table
{
	var $col = array(
	'iddividends' => array( 'type'=>'integer', 'require'=>true, 'size' =>'11' ),
	'stocksymbol' => array( 'type'=>'varchar', 'require'=>true, 'size' =>'11' ),
	'annualdividend' => array( 'type'=>'float', 'require'=>false, 'size' =>'11' ),
	'lastupdate' => array( 'type'=>'timestamp', 'require'=>false, 'size' =>'16' ),
	);
};
require_once( 'DB/DataObject.php' );;

class dividends_object extends DB_DataObject
{
	var $__table='dividends';
		//This is a Structures/DataGrid object
	var $iddividends;
	var $stocksymbol;
	var $annualdividend;
	var $lastupdate;
};
/*	view/QuickFormIncludes and TabbedPages.php are in the skel-app/view if required	*/
require_once( 'view/QuickFormIncludes.php' );;
require_once( 'view/TabbedPages.php' );;

class dividends_Page1 extends TabbedPage
{
	 protected function populateForm()
	{
		$this->addTabs();
		$fs = $this->form->addElement('fieldset')->setLabel('dividends page 1');
		$buttonGroup = $fs->addElement('group'); 
		$buttonGroup->addElement('submit', $this->getButtonName('back'), array('value' => '<< Back')); 
		$buttonGroup->addElement('submit', $this->getButtonName('submit'), array('value' => 'Finish')); 
		$buttonGroup->addElement('submit', $this->getButtonName('next'), array('value' => 'Next >>')); 
		$this->setDefaultAction('submit', 'empty.gif');
		$this->addGlobalSubmit();
		$iddividends = $fs->addElement('text', 'iddividends', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Index' )
			->addRule('required', 'iddividends Field Required' );
		$annualdividend = $fs->addElement('text', 'annualdividend', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Annual Dividend' )
;
		$f_date = date("Y-m-d H:i:s" );
		$this->form->addDataSource(new HTML_QuickForm2_DataSource_Array(array( 'lastupdate' => $f_date ) ) );
		$lastupdate = $fs->addElement('text', 'lastupdate', array('size' => 16, 'maxlength' => 16) )
			->setLabel( 'Last Update' )
			->addFilter( 'trim' )
;
	}
}
